-- FY 2024 therapy claim


create or replace table tmp_1m.kn_therapy_pr_rehab_tin_fy2024 as 
select
	a.gal_mbi_hicn_fnl as mbi
	, a.prov_tin
	, a.fst_srvc_month
	, a.fst_srvc_year
	, a.component
	, a.service_code as hce_service_code
    , a.allw_amt_fnl
    , a.net_pd_amt_fnl
    , a.eventkey as id
from fichsrv.cosmos_pr as a
where a.fst_srvc_year = 2024
--	and service_code = 'PR_REHABSERV'
	and a.tfm_include_flag = 1
    and a.global_cap = 'NA'
    and a.product_level_3_fnl not in ('INSTITUTIONAL')
--    and a.plan_level_2_fnl not in ('PFFS')
--    and a.special_network not in ('ERICKSON')
--    and a.st_abbr_cd = a.market_fnl
--    and a.prov_prtcp_sts_cd = 'P'
--    and (substring(coalesce(a.bil_typ_cd,'0'), 1, 1) <> '3')
--    and (a.ama_pl_of_srvc_cd <> '12')
    and (
        a.proc_cd in 
        ('92507','92508','92526','97012','97016','97018','97022','97024','97026','97028',
		 '97032','97033','97034','97035','97036','97039','97110','97112','97113','97116',
         '97124','97139','97140','97150','97164','97168','97530','97533','97535','97537',
         '97542','97545','97546','97750','97755','97760','97761','97799','G0283',
         '98940','98941','98942')
        or a.rvnu_cd in 
        ('0430','0431','0432','0433','0434','0439','0420','0421','0422','0423','0424','0429',
         '0440','0441','0442','0443','0444','0449')
    )
    and a.proc_cd not in 
    ('92630','92633','97001','97002','97003','97004','97545','97546','98943','G0129','G0151',
     'G0152','G9041','G9043','G9044','S9128','S9129','S9131')
union all
select
	a.gal_mbi_hicn_fnl as mbi
	, a.prov_tin
	, a.fst_srvc_month
	, a.fst_srvc_year
	, a.component
	, a.hce_service_code
    , a.allw_amt_fnl
    , a.net_pd_amt_fnl
    , a.eventkey as id
from fichsrv.cosmos_op as a
where a.fst_srvc_year = 2024
--	and hce_service_code = 'PR_REHABSERV'
	and a.tfm_include_flag = 1
    and a.global_cap = 'NA'
    and a.product_level_3_fnl not in ('INSTITUTIONAL','DUAL')
    and a.plan_level_2_fnl not in ('PFFS')
    and a.special_network not in ('ERICKSON')
    and a.st_abbr_cd = a.market_fnl
    and a.prov_prtcp_sts_cd = 'P'
    and (substring(coalesce(a.bil_typ_cd,'0'), 1, 1) <> '3')
    and (a.ama_pl_of_srvc_cd <> '12')
    and (
        a.proc_cd in 
        ('92507','92508','92526','97012','97016','97018','97022','97024','97026','97028',
		 '97032','97033','97034','97035','97036','97039','97110','97112','97113','97116',
         '97124','97139','97140','97150','97164','97168','97530','97533','97535','97537',
         '97542','97545','97546','97750','97755','97760','97761','97799','G0283',
         '98940','98941','98942')
        or a.rvnu_cd in 
        ('0430','0431','0432','0433','0434','0439','0420','0421','0422','0423','0424','0429',
         '0440','0441','0442','0443','0444','0449')
    )
    and a.proc_cd not in 
    ('92630','92633','97001','97002','97003','97004','97545','97546','98943','G0129','G0151',
     'G0152','G9041','G9043','G9044','S9128','S9129','S9131')
;
     

create or replace table tmp_1m.kn_therapy_pr_rehab_tin_fy2024_sum as
select
	a.prov_tin
	, a.fst_srvc_month
	, a.fst_srvc_year
	, a.hce_service_code
	, a.component
	, count(distinct mbi) as mm
    , sum(a.allw_amt_fnl) as allowed
    , sum(a.net_pd_amt_fnl) as paid
    , count(distinct id) as visits
from tmp_1m.kn_therapy_pr_rehab_tin_fy2024 as a 
group by 1,2,3,4,5
;

select sum(allowed) from tmp_1m.kn_therapy_pr_rehab_tin_fy2024_sum;
-- 413127214.31 with plan_level_2_fnl -> ama_pl_srvc_cd 
-- 633721205.84 without plan_level_2_fnl -> ama_pl_srvc_cd 


create or replace table tmp_1m.kn_therapy_pr_rehab_tin_spent_fy2024 as
select 
	prov_tin
	, sum(allw_amt_fnl) as allowed 
from fichsrv.cosmos_pr as a
where a.fst_srvc_year = 2024
	and service_code = 'PR_REHABSERV'
	and a.tfm_include_flag = 1
    and a.global_cap = 'NA'
    and a.product_level_3_fnl not in ('INSTITUTIONAL')
group by 1



select hce_service_code, component, sum(allowed)
from tmp_1m.kn_therapy_pr_rehab_tin_fy2024_sum
group by 1,2


select prov_tin, sum(allowed)
from tmp_1m.kn_therapy_pr_rehab_tin_fy2024_sum
where hce_service_code = 'PR_REHABSERV'
group by 1




select admit_act_month, sum(case_count)
from tmp_1m.ec_ip_dataset_loc_01072026
group by 1
order by 1


select fin_inc_month, fin_market, MnR_TOTAL_FFS_FLAG, cns_dual_flag, TOTAL_OAH_FLAG, sum(membership)
from tmp_1m.ec_ip_dataset_12242025_mm
where fin_market in ('OK','NC','NM','NV','OH','TX')
	and fin_inc_year = 2024
group by 1,2,3,4,5
order by 1

select fin_inc_month, fin_market, MnR_TOTAL_FFS_FLAG, cns_dual_flag, TOTAL_OAH_FLAG, sum(membership)
from tmp_1m.ec_ip_dataset_12172025_mm
where fin_market in ('NC')
	and fin_inc_month = '202401'
group by 1,2,3,4,5
order by 1


select ADMIT_ACT_MONTH , fin_market, MnR_TOTAL_FFS_FLAG, cns_dual_flag, TOTAL_OAH_FLAG, sum(membership), sum(case_count), sum(PERSISTENT_ADR_CNT)
from tmp_1m.ec_ip_dataset_loc_12172025
where fin_market in ('OK','NC','NM','NV','OH','TX')
	and ADMIT_ACT_MONTH in ('202401')
group by 1,2,3,4,5
order by 1

select ADMIT_ACT_MONTH , fin_market, MnR_TOTAL_FFS_FLAG, cns_dual_flag, TOTAL_OAH_FLAG, sum(membership), sum(case_count), sum(PERSISTENT_ADR_CNT)
from tmp_1m.kn_ip_dataset_loc_01072026
where fin_market in ('OK','NC','NM','NV','OH','TX')
	and ADMIT_ACT_MONTH in ('202501')
group by 1,2,3,4,5
order by 1


select ADMIT_ACT_MONTH , fin_market, MnR_TOTAL_FFS_FLAG, cns_dual_flag, TOTAL_OAH_FLAG, sum(membership), sum(case_count), sum(PERSISTENT_ADR_CNT)
from tmp_1m.kn_ip_dataset_loc_01072026
where fin_market in ('OK','NC','NM','NV','OH','TX')
	and ADMIT_ACT_MONTH in ('202401')
group by 1,2,3,4,5
order by 1


select sum(membership), sum(case_count)
from tmp_1m.kn_ip_dataset_loc_01072026 
where ADMIT_ACT_MONTH in ('202401') and mnr_total_ffs_flag = 1


select sum(case_count)
from TMP_1M.kn_IP_DATASET_LOC_01072026
where mnr_total_ffs_flag = 1 and admit_act_month = '202401'



select
	fin_market
	,CASE WHEN ((a.fin_brand in('C&S') and a.migration_source <> 'OAH' and a.global_cap = 'NA' and a.fin_product_level_3='DUAL' AND
		a.SGR_SOURCE_NAME in('COSMOS','CSP')) OR (a.fin_inc_year ='2024' AND a.fin_brand in ('C&S')
		AND a.GLOBAL_CAP = 'NA' AND a.SGR_SOURCE_NAME IN ('COSMOS','CSP') AND a.MIGRATION_SOURCE = 'OAH' AND a.FIN_STATE = 'MD')) then 1 else 0 end as CnS_Dual_flag 
	, sum(fin_member_cnt)
from fichsrv.tre_membership as a 
where fin_market in ('OK','NC','NM','NV','OH','TX')
	and fin_inc_month in ('202501')
group by
	fin_market
	,CASE WHEN ((a.fin_brand in('C&S') and a.migration_source <> 'OAH' and a.global_cap = 'NA' and a.fin_product_level_3='DUAL' AND
		a.SGR_SOURCE_NAME in('COSMOS','CSP')) OR (a.fin_inc_year ='2024' AND a.fin_brand in ('C&S')
		AND a.GLOBAL_CAP = 'NA' AND a.SGR_SOURCE_NAME IN ('COSMOS','CSP') AND a.MIGRATION_SOURCE = 'OAH' AND a.FIN_STATE = 'MD')) then 1 else 0 end
	




select ADMIT_ACT_MONTH , sum(membership), sum(case_count), sum(PERSISTENT_ADR_CNT)
from tmp_1m.ec_ip_dataset_loc_12172025
where ADMIT_ACT_MONTH in ('202401', '202402', '202403', '202501', '202502', '202503')
and MNR_TOTAL_FFS_FLAG = 1
group by 1
order by 1
;


select ADMIT_ACT_MONTH , sum(membership), sum(case_count), sum(PERSISTENT_ADR_CNT)
from tmp_1m.ec_ip_dataset_loc_01072026
where ADMIT_ACT_MONTH in ('202401', '202402', '202403', '202501', '202502', '202503')
and MNR_TOTAL_FFS_FLAG = 1
group by 1
order by 1
;


