from fichsrv.tre_membership
where (
    (
        business_segment = 'CnS'
        and fin_brand in ('C&S')
        and migration_source <> 'OAH'
        and global_cap = 'NA'
        and fin_product_level_3 = 'DUAL'
        and sgr_source_name in ('COSMOS', 'CSP')
