    or (
        year(hce_dt) = 2024
        and business_segment = 'CnS'
        and fin_brand in ('C&S')
        and global_cap = 'NA'
        and sgr_source_name in ('COSMOS', 'CSP')
        and migration_source = 'OAH'
        and fin_state = 'MD'
    )
)
and fin_market in ('OH')
	and fin_inc_month in ('202401', '202402', '202403')
group by 1,2,3,4,5
order by 1






